 36→func runAdopt(yes bool, projectPath string) error {
 37→	// Resolve project path
 38→	if projectPath == "" {
 39→		cwd, err := os.Getwd()
 40→		if err != nil {
 41→			return fmt.Errorf("getting cwd: %w", err)
 42→		}
 43→		projectPath = cwd
 44→	}
 45→	absPath, err := filepath.Abs(projectPath)
 46→	if err != nil {
 47→		return fmt.Errorf("resolving project path: %w", err)
 48→	}
 49→	projectPath = absPath
 50→
 51→	fmt.Printf("Adopting agentsea in %s\n\n", projectPath)
 52→
 53→	// Step 1: Ensure workspace exists (run init if needed)
 54→	ws, err := workspace.Detect()
 55→	if err != nil {
 56→		fmt.Println("No existing workspace detected. Running sea init...")
 57→		if err := runInit("", projectPath); err != nil {
 58→			return fmt.Errorf("init failed: %w", err)
 59→		}
 60→		fmt.Println()
 61→		ws, err = workspace.Detect()
 62→		if err != nil {
 63→			return fmt.Errorf("workspace not found after init: %w", err)
 64→		}
 65→	} else {
 66→		fmt.Printf("Workspace found at %s\n\n", ws.Dir)
 67→	}
 68→
 69→	changed := false
 70→
 71→	// Step 2: Detect toolchains
 72→	mounts := detectToolchains()
 73→	if len(mounts) > 0 {
 74→		fmt.Println("── Detected Toolchains ────────────────────────────")
 75→		for _, m := range mounts {
 76→			fmt.Printf("  %s\n", m)
 77→		}
 78→		fmt.Println()
 79→		if yes || askYesNo("Add these as read-only mounts in workspace.yaml?", true) {
 80→			// Merge with existing, avoiding duplicates
 81→			existing := make(map[string]bool)
 82→			for _, m := range ws.Config.ExtraROMounts {
 83→				existing[m] = true
 84→			}
 85→			for _, m := range mounts {
 86→				if !existing[m] {
 87→					ws.Config.ExtraROMounts = append(ws.Config.ExtraROMounts, m)
 88→					changed = true
 89→				}
 90→			}
 91→		}
 92→		fmt.Println()
 93→	} else {
 94→		fmt.Println("No common toolchain directories detected.")
 95→		fmt.Println()
 96→	}
 97→
 98→	// Step 3: Detect env vars
 99→	envVars := detectEnvVars(projectPath)
100→	if len(envVars) > 0 {
101→		fmt.Println("── Detected Environment Variables ─────────────────")
102→		for k, v := range envVars {
103→			display := v
104→			if len(display) > 40 {
105→				display = display[:37] + "..."
106→			}
107→			fmt.Printf("  %s=%s\n", k, display)
108→		}
109→		fmt.Println()
110→		if yes || askYesNo("Add these to agent_env in workspace.yaml?", true) {
111→			if ws.Config.AgentEnv == nil {
112→				ws.Config.AgentEnv = make(map[string]string)
113→			}
114→			for k, v := range envVars {
115→				if _, exists := ws.Config.AgentEnv[k]; !exists {
116→					ws.Config.AgentEnv[k] = v
117→					changed = true
118→				}
119→			}
120→		}
121→		fmt.Println()
122→	} else {
123→		fmt.Println("No .env files detected.")
124→		fmt.Println()
125→	}
126→
127→	// Step 4: Detect AGENTS.md / existing agent config
128→	if err := detectAgentConfigs(projectPath, yes); err != nil {
129→		fmt.Printf("  Warning: AGENTS.md rewrite failed: %v\n", err)
130→		fmt.Println("  You can manually update AGENTS.md later.")
131→	}
132→
133→	// Step 5: Write updated workspace.yaml if changed
134→	if changed {
135→		yamlData, err := yaml.Marshal(&ws.Config)
136→		if err != nil {
137→			return fmt.Errorf("marshaling workspace config: %w", err)
138→		}
139→		if err := os.WriteFile(filepath.Join(ws.Dir, "workspace.yaml"), yamlData, 0644); err != nil {
140→			return fmt.Errorf("writing workspace.yaml: %w", err)
141→		}
142→		fmt.Println("Updated workspace.yaml")
143→	} else {
144→		fmt.Println("No changes to workspace.yaml")
145→	}
146→
147→	// Step 6: Run doctor
148→	fmt.Println("\n── Running doctor ─────────────────────────────────")
149→	if err := runDoctor(); err != nil {
150→		fmt.Printf("\nDoctor reported issues (see above). Fix them and re-run: sea doctor\n")
151→	}
152→
153→	// Step 7: Summary
154→	fmt.Println("\n── Adoption complete ──────────────────────────────")
155→	fmt.Printf("  Workspace: %s\n", ws.Dir)
156→	if len(ws.Config.ExtraROMounts) > 0 {
157→		fmt.Printf("  Read-only mounts: %d\n", len(ws.Config.ExtraROMounts))
158→	}
159→	if len(ws.Config.AgentEnv) > 0 {
160→		fmt.Printf("  Agent env vars: %d\n", len(ws.Config.AgentEnv))
161→	}
162→
163→	return nil
164→}
