293→// runClaudePrint is the function used to call claude --print. It is a variable so tests can replace it.
294→var runClaudePrint = func(prompt string, stdin string) (string, error) {
295→	cmd := exec.Command("claude", "--print", "-p", prompt)
296→	cmd.Stdin = strings.NewReader(stdin)
297→	var stdout, stderr bytes.Buffer
298→	cmd.Stdout = &stdout
299→	cmd.Stderr = &stderr
300→	if err := cmd.Run(); err != nil {
301→		return "", fmt.Errorf("%w: %s", err, stderr.String())
302→	}
303→	return stdout.String(), nil
304→}
