335→// rewriteAgentsMd uses claude --print to rewrite AGENTS.md, shows a diff, and asks for confirmation.
336→func rewriteAgentsMd(path string, yes bool) error {
337→	original, err := os.ReadFile(path)
338→	if err != nil {
339→		return fmt.Errorf("reading AGENTS.md: %w", err)
340→	}
341→
342→	fmt.Println("  Rewriting AGENTS.md with claude --print...")
343→	rewritten, err := runClaudePrint(agentsMdRewritePrompt, string(original))
344→	if err != nil {
345→		return fmt.Errorf("claude --print failed: %w", err)
346→	}
347→
348→	rewritten = strings.TrimRight(rewritten, "\n") + "\n"
349→
350→	if rewritten == string(original) {
351→		fmt.Println("  No changes needed — AGENTS.md is already up to date.")
352→		fmt.Println()
353→		return nil
354→	}
355→
356→	// Show diff
357→	fmt.Println()
358→	fmt.Println("── Proposed AGENTS.md changes ─────────────────────")
359→	showSimpleDiff(string(original), rewritten)
360→	fmt.Println("───────────────────────────────────────────────────")
361→	fmt.Println()
362→
363→	if yes || askYesNo("Apply these changes to AGENTS.md?", true) {
364→		if err := os.WriteFile(path, []byte(rewritten), 0644); err != nil {
365→			return fmt.Errorf("writing AGENTS.md: %w", err)
366→		}
367→		fmt.Println("  AGENTS.md updated.")
368→	} else {
369→		fmt.Println("  Skipped AGENTS.md rewrite.")
370→	}
371→	fmt.Println()
372→
373→	return nil
374→}
