376→// showSimpleDiff prints a basic line-by-line diff between two strings.
377→func showSimpleDiff(old, new string) {
378→	oldLines := strings.Split(old, "\n")
379→	newLines := strings.Split(new, "\n")
380→
381→	// Simple approach: show removed lines with -, added lines with +
382→	oldSet := make(map[string]int)
383→	for _, l := range oldLines {
384→		oldSet[l]++
385→	}
386→	newSet := make(map[string]int)
387→	for _, l := range newLines {
388→		newSet[l]++
389→	}
390→
391→	for _, l := range oldLines {
392→		if newSet[l] <= 0 {
393→			fmt.Printf("  - %s\n", l)
394→		} else {
395→			newSet[l]--
396→		}
397→	}
398→	for _, l := range newLines {
399→		if oldSet[l] <= 0 {
400→			fmt.Printf("  + %s\n", l)
401→		} else {
402→			oldSet[l]--
403→		}
404→	}
405→}
