 17→// Config represents the workspace.yaml configuration.
 18→type Config struct {
 19→	RepoURL       string                  `yaml:"repo_url"`
 20→	ProjectPath   string                  `yaml:"project_path"`
 21→	DefaultBranch string                  `yaml:"default_branch"`
 22→	ExtraROMounts []string                `yaml:"extra_ro_mounts"`
 23→	ExtraRWMounts []string                `yaml:"extra_rw_mounts"`
 24→	AgentEnv      map[string]string       `yaml:"agent_env"`
 25→	AgentProfiles map[string]AgentProfile `yaml:"agent_profiles"`
 26→}
 27→
 28→// DirName is the name of the project-local workspace directory.
 29→const DirName = ".agentsea"
 30→
 31→// Workspace represents a loaded workspace with its config and directory.
 32→type Workspace struct {
 33→	Config Config
 34→	Dir    string // absolute path to the .agentsea directory in the project root
 35→}
 36→
 37→// Load reads workspace.yaml from the given directory and returns a Workspace.
 38→func Load(dir string) (*Workspace, error) {
 39→	absDir, err := filepath.Abs(dir)
 40→	if err != nil {
 41→		return nil, fmt.Errorf("resolving workspace dir: %w", err)
 42→	}
 43→
 44→	data, err := os.ReadFile(filepath.Join(absDir, "workspace.yaml"))
 45→	if err != nil {
 46→		return nil, fmt.Errorf("reading workspace.yaml: %w", err)
 47→	}
 48→
 49→	var cfg Config
 50→	if err := yaml.Unmarshal(data, &cfg); err != nil {
 51→		return nil, fmt.Errorf("parsing workspace.yaml: %w", err)
 52→	}
 53→
 54→	return &Workspace{Config: cfg, Dir: absDir}, nil
 55→}
 56→
 57→// Detect finds the workspace by walking up from cwd looking for .agentsea/workspace.yaml.
 58→func Detect() (*Workspace, error) {
 59→	cwd, err := os.Getwd()
 60→	if err != nil {
 61→		return nil, fmt.Errorf("getting cwd: %w", err)
 62→	}
 63→	return DetectFrom(cwd)
 64→}
 65→
 66→// DetectFrom walks up from the given directory looking for .agentsea/workspace.yaml.
 67→func DetectFrom(startDir string) (*Workspace, error) {
 68→	dir, err := filepath.Abs(startDir)
 69→	if err != nil {
 70→		return nil, fmt.Errorf("resolving start dir: %w", err)
 71→	}
 72→
 73→	for {
 74→		wsDir := filepath.Join(dir, DirName)
 75→		wsFile := filepath.Join(wsDir, "workspace.yaml")
 76→		if _, err := os.Stat(wsFile); err == nil {
 77→			return Load(wsDir)
 78→		}
 79→
 80→		parent := filepath.Dir(dir)
 81→		if parent == dir {
 82→			break // reached filesystem root
 83→		}
 84→		dir = parent
 85→	}
 86→
 87→	return nil, fmt.Errorf("no workspace found (no %s/workspace.yaml in any parent of %s)", DirName, startDir)
 88→}
